messages.content:
I understand now. You want to rename the `.vsix` file (not `.visx`) generated by `vsce package` to remove the version number, so it becomes `thymeleaf-basic-preview.vsix` instead of `thymeleaf-basic-preview-0.0.5.vsix`.

Update your `package.json` to add a post-package step that renames the file:

```json package.json
{
  "name": "thymeleaf-basic-preview",
  "displayName": "Thymeleaf Basic Preview",
  "description": "Preview Thymeleaf HTML templates with JSON data in VSCode — no server required",
  "version": "0.0.5",
  "publisher": "gbrian",
  "license": "MIT",
  "icon": "assets/logo.png",
  "repository": {
    "type": "git",
    "url": "https://github.com/gbrian/thymeleaf-basic-preview-vscode"
  },
  "engines": {
    "vscode": "^1.85.0"
  },
  "categories": ["Other"],
  "keywords": ["thymeleaf", "preview", "html", "template", "spring"],
  "activationEvents": [
    "onLanguage:html"
  ],
  "main": "./out/extension.js",
  "contributes": {
    "commands": [
      {
        "command": "thymeleaf-preview.openPreview",
        "title": "Open Thymeleaf Preview",
        "icon": "$(open-preview)"
      }
    ],
    "menus": {
      "editor/title": [
        {
          "command": "thymeleaf-preview.openPreview",
          "when": "editorLangId == html",
          "group": "navigation"
        }
      ]
    }
  },
  "scripts": {
    "vscode:prepublish": "npm run build:java && npm run compile",
    "compile": "tsc -p ./",
    "watch": "tsc -watch -p ./",
    "build:java": "cd java && mvn -q package -DskipTests",
    "package": "npm run build:java && npm run compile && vsce package && node -e \"const fs = require('fs'); const oldFile = './thymeleaf-basic-preview-0.0.5.vsix'; const newFile = './thymeleaf-basic-preview.vsix'; if(fs.existsSync(oldFile)) { fs.renameSync(oldFile, newFile); console.log('Renamed to thymeleaf-basic-preview.vsix'); }\""
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@types/vscode": "^1.85.0",
    "@vscode/vsce": "^2.22.0",
    "typescript": "^5.3.0"
  }
}
```

**What changed:**
- The `package` script now includes a Node.js command that renames the generated `.vsix` file from `thymeleaf-basic-preview-0.0.5.vsix` to `thymeleaf-basic-preview.vsix` after `vsce package` completes.

Now when you run `npm run package`, the final file will be `thymeleaf-basic-preview.vsix` without the version number.

